app.post('/search', async (req, res) => {
  try {
    const {
      index,
      query_params,
      script_score,
      function_score,
      aggregations,
      sort,
      from = 0,
      size = 10,
      source,
      highlight
    } = req.body;

    if (!index) {
      return res.status(400).json({ error: 'Index name is required' });
    }

    const builder = new QueryBuilder();
    let finalQuery;

    if (query_params) {
      const baseQuery = builder.buildBoolQuery(query_params);

      if (script_score) {
        finalQuery = builder.buildScriptScoreQuery(baseQuery, script_score);
      } else if (function_score) {
        finalQuery = builder.buildFunctionScoreQuery(baseQuery, function_score);
      } else {
        finalQuery = baseQuery;
      }
    } else {
      finalQuery = { match_all: {} };
    }

    const searchBody = {
      query: finalQuery,
      from,
      size
    };

    if (aggregations) {
      searchBody.aggs = builder.buildAggregations(aggregations);
    }

    if (sort) {
      searchBody.sort = sort;
    }

    if (source !== undefined) {
      searchBody._source = source;
    }

    if (highlight) {
      searchBody.highlight = highlight;
    }

    const result = await client.search({
      index,
      body: searchBody
    });

    res.json({
      total: result.hits.total,
      hits: result.hits.hits,
      aggregations: result.aggregations,
      took: result.took
    });

  } catch (error) {
    console.error('Search error:', error);
    res.status(500).json({
      error: 'Search failed',
      message: error.message,
      details: error.meta?.body?.error
    });
  }
});

